// ── Filter to today's transactions and compute summary stats ──

const allRows = $input.all().map(item => item.json);

// Get today's date in YYYY-MM-DD format (IST)
const now = new Date();
const istOffset = 5.5 * 60 * 60 * 1000;
const ist = new Date(now.getTime() + istOffset);
const todayStr = ist.toISOString().split('T')[0];

// Filter rows to only today's transactions
const todayRows = allRows.filter(row => {
  if (!row.timestamp) return false;
  const rowDate = new Date(row.timestamp);
  // Skip rows whose timestamp can't be parsed (avoids "Invalid time value")
  if (isNaN(rowDate.getTime())) return false;
  const rowIST = new Date(rowDate.getTime() + istOffset);
  return rowIST.toISOString().split('T')[0] === todayStr;
});

// If no transactions today, return a "nothing spent" summary
if (todayRows.length === 0) {
  return [{
    json: {
      hasData: false,
      date: todayStr,
      total_spend: 0,
      top_category: 'None',
      transaction_count: 0,
      need_pct: 0,
      summaryText: `📊 Daily Summary — ${todayStr}\n\nNo expenses logged today. Nice! 🎉`
    }
  }];
}

// Calculate totals
const totalSpend = todayRows.reduce((sum, row) => sum + (parseFloat(row.amount) || 0), 0);
const transactionCount = todayRows.length;

// Count by category to find top category
const categoryTotals = {};
for (const row of todayRows) {
  const cat = row.category || 'Uncategorized';
  categoryTotals[cat] = (categoryTotals[cat] || 0) + (parseFloat(row.amount) || 0);
}
const topCategory = Object.entries(categoryTotals)
  .sort((a, b) => b[1] - a[1])[0][0];

// Calculate need vs want percentage
const needTotal = todayRows
  .filter(row => (row.need_or_want || '').toLowerCase() === 'need')
  .reduce((sum, row) => sum + (parseFloat(row.amount) || 0), 0);
const needPct = totalSpend > 0 ? Math.round((needTotal / totalSpend) * 100) : 0;
const wantPct = 100 - needPct;

// Build the category breakdown lines
const categoryLines = Object.entries(categoryTotals)
  .sort((a, b) => b[1] - a[1])
  .map(([cat, amt]) => `  • ${cat}: ₹${amt}`)
  .join('\n');

// Format the Telegram message
const summaryText = `📊 Daily Summary — ${todayStr}

💰 Total: ₹${totalSpend}
📝 Transactions: ${transactionCount}
🏆 Top category: ${topCategory}

📋 Breakdown:
${categoryLines}

⚖️ Needs: ${needPct}% | Wants: ${wantPct}%`;

return [{
  json: {
    hasData: true,
    date: todayStr,
    total_spend: totalSpend,
    top_category: topCategory,
    transaction_count: transactionCount,
    need_pct: needPct,
    summaryText
  }
}];
